const logResponse = $input.first().json;
const logId = Array.isArray(logResponse) ? logResponse[0].id : logResponse.id;
const startTime = $('Set Start Time').first().json.start_time;

const accounts = [
  { act_id: 'act_654279452039150', brand_id: 1 },
  { act_id: 'act_382359687910745', brand_id: 2 },
  { act_id: 'act_1496776195316716', brand_id: 3 }
];

return accounts.map(a => ({ json: { ...a, log_id: logId, start_time: startTime } }));

const input = $input.first().json;
const brandId = $('Split Ad Accounts').first().json.brand_id;
const ads = input.data || [];
const allRows = [];

for (const ad of ads) {
  const adName = ad.name || 'Unknown';
  const campaignName = (ad.campaign && ad.campaign.name) ? ad.campaign.name : null;
  const insights = (ad.insights && ad.insights.data) ? ad.insights.data : [];

  if (insights.length === 0) continue;

  // Sort insights by date ascending for fatigue calculation
  insights.sort((a, b) => a.date_start.localeCompare(b.date_start));

  // Baseline CTR: use the oldest data point
  const baselineCtr = parseFloat(insights[0].ctr || 0);

  // Recent 3-day avg CTR
  const recent3 = insights.slice(-3);
  const recentAvgCtr = recent3.reduce((sum, d) => sum + parseFloat(d.ctr || 0), 0) / recent3.length;

  for (const day of insights) {
    const actions = day.actions || [];
    const leadAction = actions.find(a => a.action_type === 'lead');
    const leads = leadAction ? parseInt(leadAction.value, 10) : 0;
    const freq = parseFloat(day.frequency || 0);
    const ctr = parseFloat(day.ctr || 0);

    // Fatigue status calculation
    let fatigueStatus = 'healthy';
    if (baselineCtr > 0) {
      const ctrDrop = (baselineCtr - recentAvgCtr) / baselineCtr;
      if (ctrDrop > 0.20 && freq > 3.0) {
        fatigueStatus = 'fatigued';
      } else if (ctrDrop > 0.10 || freq > 2.5) {
        fatigueStatus = 'watch';
      }
    }

    allRows.push({
      date: day.date_start,
      brand_id: brandId,
      platform: 'meta',
      campaign_name: campaignName,
      ad_name: adName,
      creative_url: null,
      spend: parseFloat(day.spend || 0),
      impressions: parseInt(day.impressions || 0, 10),
      clicks: parseInt(day.clicks || 0, 10),
      ctr_pct: Math.round(ctr * 100) / 100,
      frequency: Math.round(freq * 100) / 100,
      cpm: Math.round(parseFloat(day.cpm || 0) * 100) / 100,
      leads: leads,
      fatigue_status: fatigueStatus
    });
  }
}

return allRows.map(r => ({ json: r }));

const startTime = $('Set Start Time').first().json.start_time;
const logId = $('Split Ad Accounts').first().json.log_id;
const totalRows = $input.all().length;
const durationSec = Math.round((Date.now() - startTime) / 1000);

return [{ json: {
  log_id: logId,
  status: 'success',
  rows_upserted: totalRows,
  duration_sec: durationSec
}}];

const startTime = $('Set Start Time').first().json.start_time;
const logId = $('Split Ad Accounts').first().json.log_id;
const durationSec = Math.round((Date.now() - startTime) / 1000);
const errorMsg = $input.first().json.message || 'Unknown error';

return [{ json: {
  log_id: logId,
  status: 'failed',
  error_message: errorMsg.substring(0, 500),
